const destinations = [
  { ciudad: 'El Cocuy', query: 'El Cocuy,CO' },
  { ciudad: 'Santa Marta', query: 'Santa Marta,CO' },
  { ciudad: 'Leticia', query: 'Leticia,CO' },
  { ciudad: 'Riohacha', query: 'Riohacha,CO' },
  { ciudad: 'Bogota', query: 'Bogota,CO' },
];

return destinations.map((d) => ({ json: d }));

const dest = $('Por ciudad').item.json;
const owm = $input.first().json;

if (!owm?.main) {
  throw new Error(
    `OpenWeatherMap sin datos para ${dest.ciudad}: ${JSON.stringify(owm).slice(0, 240)}`,
  );
}

const fetchedAt = new Date().toISOString();
const hour = new Date();
hour.setUTCMinutes(0, 0, 0);
const snapshotHour = hour.toISOString();

const windMs = Number(owm.wind?.speed ?? 0);

return [
  {
    json: {
      ciudad: dest.ciudad,
      temperatura: Number(owm.main.temp),
      sensacion_termica: Number(owm.main.feels_like),
      humedad: Number(owm.main.humidity),
      descripcion: owm.weather?.[0]?.description ?? '',
      viento_kmh: Math.round(windMs * 3.6 * 10) / 10,
      presion: owm.main.pressure ?? null,
      visibilidad_m: owm.visibility ?? null,
      icono: owm.weather?.[0]?.icon ?? null,
      condicion_id: owm.weather?.[0]?.id ?? null,
      lat: owm.coord?.lat ?? null,
      lon: owm.coord?.lon ?? null,
      nubes_pct: owm.clouds?.all ?? null,
      fetched_at: fetchedAt,
      snapshot_hour: snapshotHour,
    },
  },
];

const baseUrl = ($env.SUPABASE_URL || '').replace(/\/$/, '');
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY || '';

if (!baseUrl || !serviceKey) {
  throw new Error(
    'Faltan SUPABASE_URL o SUPABASE_SERVICE_ROLE_KEY en n8n ($env; npm run n8n:briselda)',
  );
}

const upsertUrl = `${baseUrl}/rest/v1/destination_weather?on_conflict=ciudad,snapshot_hour`;
const headers = {
  apikey: serviceKey,
  Authorization: `Bearer ${serviceKey}`,
  'Content-Type': 'application/json',
  'Content-Profile': 'briselda',
  Prefer: 'resolution=merge-duplicates,return=representation',
};

const saved = [];

for (const item of $input.all()) {
  const j = item.json;
  const row = {
    ciudad: j.ciudad,
    temperatura: j.temperatura,
    sensacion_termica: j.sensacion_termica,
    humedad: j.humedad,
    descripcion: j.descripcion,
    viento_kmh: j.viento_kmh,
    presion: j.presion,
    visibilidad_m: j.visibilidad_m,
    icono: j.icono,
    condicion_id: j.condicion_id,
    lat: j.lat,
    lon: j.lon,
    nubes_pct: j.nubes_pct,
    fetched_at: j.fetched_at,
    snapshot_hour: j.snapshot_hour,
  };

  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: upsertUrl,
    headers,
    body: row,
    json: true,
  });

  saved.push({ json: { ...row, supabase: res } });
}

return saved;
